import{_ as s,c as a,o as n,a as t}from"./chunks/plugin-vue_export-helper.dqZ0aIgD.js";const h=JSON.parse('{"title":"Controller Resource Sizing","description":"Right-size the Lynq controller pod with real observed data — sub-100m CPU and sub-120MB memory at 300+ LynqNodes — and understand why resources scale the way they do.","frontmatter":{"description":"Right-size the Lynq controller pod with real observed data — sub-100m CPU and sub-120MB memory at 300+ LynqNodes — and understand why resources scale the way they do."},"headers":[],"relativePath":"resource-sizing.md","filePath":"resource-sizing.md","lastUpdated":1779171623000}'),o={name:"resource-sizing.md"};function r(l,e,i,c,d,p){return n(),a("div",null,[...e[0]||(e[0]=[t(`<h1 id="controller-resource-sizing" tabindex="-1">Controller Resource Sizing <a class="header-anchor" href="#controller-resource-sizing" aria-label="Permalink to &quot;Controller Resource Sizing&quot;">​</a></h1><p>Right-size the Lynq controller pod. This page explains <em>why</em> Lynq uses resources the way it does, then gives you the numbers to set <code>requests</code> and <code>limits</code> confidently.</p><div class="tip custom-block"><p class="custom-block-title">Time to working</p><p>5 minutes to pick the right tier and update your Helm values or manager YAML.</p></div><h2 id="observed-usage-real-data" tabindex="-1">Observed Usage (Real Data) <a class="header-anchor" href="#observed-usage-real-data" aria-label="Permalink to &quot;Observed Usage (Real Data)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Environment</th><th>LynqNodes</th><th>CPU (observed)</th><th>Memory (observed)</th></tr></thead><tbody><tr><td>Small</td><td>5</td><td><strong>0 – 5 m</strong></td><td><strong>10 – 60 MB</strong></td></tr><tr><td>Large</td><td><strong>300+</strong></td><td><strong>&lt; 100 m</strong></td><td><strong>&lt; 120 MB</strong></td></tr></tbody></table><p><strong>Benchmark environment for the 300+ data point:</strong></p><ul><li>1 LynqHub, multiple LynqForms across a few hundred active rows</li><li>Several thousand managed Kubernetes objects in cache</li><li>Annotation-driven skip path active (the vast majority of reconciles complete with <strong>zero child-resource API writes</strong> because <code>lynq.sh/applied-hash</code> matches the desired-spec hash)</li></ul><p>CPU is bursty — it spikes briefly during periodic force-reapply cycles (every <code>ForceReapplyInterval</code>, default 10 min) and template-change events, then drops to near-idle. Memory grows with the number of managed objects (controller-runtime informer cache) and stays roughly flat within a stable cluster. Steady-state CPU is dominated by watch event processing, not reconciliation. See <a href="./architecture.html#drift-correction">Architecture › Drift Correction</a>.</p><h2 id="why-lynq-uses-resources-this-way" tabindex="-1">Why Lynq Uses Resources This Way <a class="header-anchor" href="#why-lynq-uses-resources-this-way" aria-label="Permalink to &quot;Why Lynq Uses Resources This Way&quot;">​</a></h2><p>Understanding the two resource drivers makes sizing intuitive.</p><h3 id="cpu-—-driven-by-reconciliation-workload" tabindex="-1">CPU — driven by reconciliation workload <a class="header-anchor" href="#cpu-—-driven-by-reconciliation-workload" aria-label="Permalink to &quot;CPU — driven by reconciliation workload&quot;">​</a></h3><p>Lynq&#39;s CPU usage is almost entirely <strong>reconciliation work</strong>, not background polling. The controller sits idle until something triggers a reconcile, then it processes work concurrently up to the <code>--node-concurrency</code> limit.</p><p>Each LynqNode reconciliation involves:</p><ol><li><strong>Template rendering</strong> — evaluate Go templates for each managed resource</li><li><strong>Dependency graph traversal</strong> — topological sort of <code>dependIds</code></li><li><strong>Kubernetes API calls</strong> — one Server-Side Apply (SSA) call <strong>per resource</strong></li><li><strong>Status update</strong> — patch the LynqNode status and conditions</li></ol><p>Steps 3 and 4 dominate. A LynqNode that manages 9 resources makes 9 SSA calls per reconcile — roughly 9× more CPU work than a LynqNode with 1 resource. This means <strong>total managed resources across all LynqNodes</strong> is the primary CPU driver, not just the node count.</p><p><strong>Why CPU is spiky:</strong> during a hub sync (every <code>syncInterval</code>, e.g. 1 minute), all out-of-date nodes are enqueued at once. CPU jumps to the peak value briefly, then falls back to near-idle as the queue drains.</p><h3 id="memory-—-driven-by-the-controller-cache" tabindex="-1">Memory — driven by the controller cache <a class="header-anchor" href="#memory-—-driven-by-the-controller-cache" aria-label="Permalink to &quot;Memory — driven by the controller cache&quot;">​</a></h3><p>The controller-runtime framework keeps an <strong>in-memory cache</strong> of every Kubernetes object it watches. This cache enables instant reads without hitting the API server on every reconcile. It is the dominant memory consumer, and it scales with <strong>total managed object count</strong>, not just LynqNode count.</p><p>What lives in the cache (benchmark environment at 220 nodes, ~1,025 managed objects):</p><table tabindex="0"><thead><tr><th>Cache contents</th><th>5 nodes estimate</th><th>220 nodes (observed)</th></tr></thead><tbody><tr><td>LynqNode CRs</td><td>~75 KB</td><td>~3.3 MB</td></tr><tr><td>Managed resources (~1,025 objects)</td><td>~0.1 MB</td><td>~70–110 MB</td></tr><tr><td>LynqHub + LynqForm CRs</td><td>~50 KB</td><td>~50 KB</td></tr><tr><td>Go runtime + controller overhead</td><td>~20–30 MB</td><td>~20–30 MB</td></tr><tr><td><strong>Total</strong></td><td><strong>~20–30 MB</strong></td><td><strong>~100–140 MB</strong></td></tr></tbody></table><p>Each cached Kubernetes object is a deserialized Go struct (roughly 70–110 KB). 1,025 objects × ~100 KB/object ≈ 100 MB, which matches the observed range.</p><p><strong>Memory is stable, not spiky:</strong> once the cache is warm it stays flat. Growth happens only when total managed object count increases.</p><h2 id="sizing-table" tabindex="-1">Sizing Table <a class="header-anchor" href="#sizing-table" aria-label="Permalink to &quot;Sizing Table&quot;">​</a></h2><p>Set <code>requests</code> to match observed usage at your expected scale. Set <code>limits</code> to 2–3× requests to absorb burst — especially for CPU.</p><p>The table below uses the benchmark resource density (avg ~4.7 managed resources per LynqNode). See <a href="#adjusting-for-different-resource-densities">Adjusting for Different Densities</a> if your forms define significantly more or fewer resources.</p><table tabindex="0"><thead><tr><th>LynqNodes</th><th>CPU request</th><th>CPU limit</th><th>Memory request</th><th>Memory limit</th></tr></thead><tbody><tr><td>&lt; 50</td><td><code>25m</code></td><td><code>100m</code></td><td><code>64Mi</code></td><td><code>128Mi</code></td></tr><tr><td>50 – 200</td><td><code>50m</code></td><td><code>200m</code></td><td><code>96Mi</code></td><td><code>192Mi</code></td></tr><tr><td>200 – 500</td><td><code>100m</code></td><td><code>300m</code></td><td><code>128Mi</code></td><td><code>256Mi</code></td></tr><tr><td>500 – 1000</td><td><code>200m</code></td><td><code>500m</code></td><td><code>256Mi</code></td><td><code>512Mi</code></td></tr><tr><td>1000+</td><td><code>500m</code></td><td><code>1000m</code></td><td><code>512Mi</code></td><td><code>1Gi</code></td></tr></tbody></table><p>These numbers are anchored to the 300+ node production observation (&lt; 100 m CPU steady-state, &lt; 120 MB memory). Limits are sized 2–3× above steady-state to absorb force-reapply bursts (every <code>ForceReapplyInterval</code>, default 10 min) and template-change events.</p><div class="warning custom-block"><p class="custom-block-title">Never set memory limit below memory request</p><p>If the pod is OOMKilled it restarts, losing its cache. On restart it must re-sync everything — causing a CPU spike and temporary reconciliation lag. Leave at least 2× headroom above observed memory.</p></div><h3 id="applying-the-limits" tabindex="-1">Applying the limits <a class="header-anchor" href="#applying-the-limits" aria-label="Permalink to &quot;Applying the limits&quot;">​</a></h3><p><strong>Helm:</strong></p><div class="language-yaml line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#6A737D;"># values.yaml</span></span>
<span class="line"><span style="color:#85E89D;">resources</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#85E89D;">  requests</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#85E89D;">    cpu</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">500m</span></span>
<span class="line"><span style="color:#85E89D;">    memory</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">256Mi</span></span>
<span class="line"><span style="color:#85E89D;">  limits</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#85E89D;">    cpu</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">1000m</span></span>
<span class="line"><span style="color:#85E89D;">    memory</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">512Mi</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p><strong>Kustomize / direct manifest:</strong></p><div class="language-yaml line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#6A737D;"># config/manager/manager.yaml</span></span>
<span class="line"><span style="color:#85E89D;">containers</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#85E89D;">name</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">manager</span></span>
<span class="line"><span style="color:#85E89D;">    resources</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#85E89D;">      requests</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#85E89D;">        cpu</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">500m</span></span>
<span class="line"><span style="color:#85E89D;">        memory</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">256Mi</span></span>
<span class="line"><span style="color:#85E89D;">      limits</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#85E89D;">        cpu</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">1000m</span></span>
<span class="line"><span style="color:#85E89D;">        memory</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">512Mi</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><h2 id="scaling-projection" tabindex="-1">Scaling Projection <a class="header-anchor" href="#scaling-projection" aria-label="Permalink to &quot;Scaling Projection&quot;">​</a></h2><p>The accurate way to project resource usage is to estimate <strong>total managed objects</strong> — the sum across all LynqForms of (LynqNodes for that form × resources defined in that form).</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span>total_managed = Σ (node_count_per_form × resources_per_form)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>CPU (steady state)  ≈ total_managed × 0.55 m</span></span>
<span class="line"><span>Memory (warm cache) ≈ 30 MB + (total_managed × 0.1 MB)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p><strong>Benchmark verification:</strong></p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span>total_managed = (74 × 9) + (73 × 3) + (73 × 2) = 666 + 219 + 146 = 1,031</span></span>
<span class="line"><span></span></span>
<span class="line"><span>CPU  ≈ 1,031 × 0.55 = 567 m  → observed 500–600 m ✓</span></span>
<span class="line"><span>Mem  ≈ 30 + 1,031 × 0.1 = 133 MB → observed 100–140 MB ✓</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p><strong>Projection table</strong> (same 3-form density as benchmark, avg ~4.7 resources/node):</p><table tabindex="0"><thead><tr><th>Active rows</th><th>LynqNodes (×3 forms)</th><th>Total managed</th><th>CPU (steady)</th><th>Memory (warm)</th></tr></thead><tbody><tr><td>~1</td><td>5</td><td>~23</td><td>~13 m</td><td>~32 MB</td></tr><tr><td>~17</td><td>50</td><td>~235</td><td>~130 m</td><td>~54 MB</td></tr><tr><td>~73</td><td>220</td><td>~1,025</td><td>~565 m</td><td>~133 MB</td></tr><tr><td>~170</td><td>500</td><td>~2,345</td><td>~1,290 m</td><td>~265 MB</td></tr><tr><td>~335</td><td>1,000</td><td>~4,690</td><td>~2,580 m</td><td>~499 MB</td></tr></tbody></table><p>These are steady-state estimates. Add 50–100% headroom for burst and reconciliation spikes.</p><h2 id="adjusting-for-different-resource-densities" tabindex="-1">Adjusting for Different Resource Densities <a class="header-anchor" href="#adjusting-for-different-resource-densities" aria-label="Permalink to &quot;Adjusting for Different Resource Densities&quot;">​</a></h2><p>If your LynqForms define significantly more or fewer resources per node than the benchmark (~4.7 avg), the <code>total_managed</code> formula is the reliable path.</p><p><strong>Example — heavier setup:</strong></p><blockquote><p>2 LynqForms, each with 15 resources per node. 100 active rows = 200 LynqNodes. <code>total_managed = 2 × 100 × 15 = 3,000</code><code>CPU ≈ 3,000 × 0.55 = 1,650 m</code> — over 1.5 cores, not the ~250 m you&#39;d get from a node-count-only estimate.</p></blockquote><p><strong>Example — lighter setup:</strong></p><blockquote><p>1 LynqForm with 3 resources per node. 500 active rows = 500 LynqNodes. <code>total_managed = 500 × 3 = 1,500</code><code>CPU ≈ 1,500 × 0.55 = 825 m</code> — less than the 500-node row in the table above suggests.</p></blockquote><p>Use <code>kubectl top pod -n lynq-system</code> early in your rollout to validate against the model.</p><h2 id="what-goes-wrong-with-under-sized-resources" tabindex="-1">What Goes Wrong with Under-sized Resources <a class="header-anchor" href="#what-goes-wrong-with-under-sized-resources" aria-label="Permalink to &quot;What Goes Wrong with Under-sized Resources&quot;">​</a></h2><h3 id="cpu-throttling" tabindex="-1">CPU throttling <a class="header-anchor" href="#cpu-throttling" aria-label="Permalink to &quot;CPU throttling&quot;">​</a></h3><p>If the CPU limit is too low, the kernel rate-limits the container. Reconciliations slow down — you&#39;ll see longer reconcile durations in <code>lynqnode_reconcile_duration_seconds</code> without any errors. Everything still works, just slower.</p><p><strong>Signal:</strong> <code>container_cpu_cfs_throttled_seconds_total</code> increases. Reconciliation P95 &gt; 15 s.</p><p><strong>Fix:</strong> raise the CPU limit, or reduce <code>--node-concurrency</code> to lower the burst peak.</p><h3 id="memory-oomkill" tabindex="-1">Memory OOMKill <a class="header-anchor" href="#memory-oomkill" aria-label="Permalink to &quot;Memory OOMKill&quot;">​</a></h3><p>If the memory limit is too close to the working set, the pod is killed and restarted when the cache fills. After restart, the controller re-builds the cache from scratch — a cold-start reconciliation wave that temporarily spikes CPU.</p><p><strong>Signal:</strong> pod restarts increasing (<code>kube_pod_container_status_restarts_total</code>). <code>OOMKilled</code> in <code>kubectl describe pod</code>.</p><p><strong>Fix:</strong> raise the memory limit. A safe floor is:</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span>memory limit ≥ 30 MB + (total_managed × 0.15 MB)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>For the benchmark at ~1,025 managed objects: <code>30 + 1,025 × 0.15 ≈ 184 MB</code> — which explains why the 200–500 node tier uses <code>256Mi</code> as the request.</p><h2 id="how-to-verify-current-usage" tabindex="-1">How to Verify Current Usage <a class="header-anchor" href="#how-to-verify-current-usage" aria-label="Permalink to &quot;How to Verify Current Usage&quot;">​</a></h2><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#6A737D;"># Live resource usage</span></span>
<span class="line"><span style="color:#B392F0;">kubectl</span><span style="color:#9ECBFF;"> top</span><span style="color:#9ECBFF;"> pod</span><span style="color:#79B8FF;"> -n</span><span style="color:#9ECBFF;"> lynq-system</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;"># See configured limits and requests</span></span>
<span class="line"><span style="color:#B392F0;">kubectl</span><span style="color:#9ECBFF;"> get</span><span style="color:#9ECBFF;"> pod</span><span style="color:#79B8FF;"> -n</span><span style="color:#9ECBFF;"> lynq-system</span><span style="color:#79B8FF;"> -l</span><span style="color:#9ECBFF;"> control-plane=controller-manager</span><span style="color:#79B8FF;"> \\</span></span>
<span class="line"><span style="color:#79B8FF;">  -o</span><span style="color:#9ECBFF;"> jsonpath=&#39;{range .items[*]}{.spec.containers[*].resources}{&quot;\\n&quot;}{end}&#39;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;"># Count total managed objects as a sizing check</span></span>
<span class="line"><span style="color:#B392F0;">kubectl</span><span style="color:#9ECBFF;"> get</span><span style="color:#9ECBFF;"> lynqnodes</span><span style="color:#79B8FF;"> -A</span><span style="color:#79B8FF;"> --no-headers</span><span style="color:#F97583;"> |</span><span style="color:#B392F0;"> wc</span><span style="color:#79B8FF;"> -l</span><span style="color:#6A737D;">   # LynqNode count</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>Prometheus query for memory headroom:</p><div class="language-promql line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span># Memory usage as % of limit (alert if &gt; 80%)</span></span>
<span class="line"><span>container_memory_working_set_bytes{container=&quot;manager&quot;, namespace=&quot;lynq-system&quot;}</span></span>
<span class="line"><span>/ container_spec_memory_limit_bytes{container=&quot;manager&quot;, namespace=&quot;lynq-system&quot;} * 100</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h2 id="concurrency-and-resource-trade-off" tabindex="-1">Concurrency and Resource Trade-off <a class="header-anchor" href="#concurrency-and-resource-trade-off" aria-label="Permalink to &quot;Concurrency and Resource Trade-off&quot;">​</a></h2><p>Higher <code>--node-concurrency</code> increases burst CPU but decreases reconciliation latency. Lower concurrency reduces the burst peak but slows down mass reconciliations.</p><p>The table below is an estimate based on the benchmark environment (220 LynqNodes, ~1,025 managed objects). Actual values depend on your resource density and cluster API server latency.</p><table tabindex="0"><thead><tr><th><code>--node-concurrency</code></th><th>Est. CPU at 220 nodes</th><th>Est. time to reconcile all 220 nodes</th></tr></thead><tbody><tr><td>5</td><td>~300 m</td><td>~60–90 s</td></tr><tr><td>10 (default)</td><td>~550 m</td><td>~30–45 s</td></tr><tr><td>20</td><td>~900 m</td><td>~15–25 s</td></tr></tbody></table><p>If you see high CPU but nodes change infrequently, reduce concurrency before raising limits.</p><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./performance.html">Performance Tuning</a> — sync intervals, dependency depth, template optimization</li><li><a href="./configuration.html">Configuration</a> — <code>--node-concurrency</code>, <code>--hub-concurrency</code>, <code>--form-concurrency</code> flags</li><li><a href="./monitoring.html">Monitoring</a> — Prometheus metrics for reconcile duration and resource usage</li><li><a href="./prometheus-queries.html">Prometheus Queries</a> — ready-to-use PromQL for sizing decisions</li></ul>`,70)])])}const m=s(o,[["render",r]]);export{h as __pageData,m as default};
